(()=>{"use strict";!function(){const t=document.querySelectorAll('.toggle input[type="checkbox"], .toggle input[type="radio"]');t&&t.forEach((t=>{let e=t.parentElement;e.setAttribute("tabindex","-1"),t.addEventListener("click",(function(){e.classList.add("toggle--ripple"),setTimeout((()=>{e.classList.remove("toggle--ripple")}),225)}))}))}()})();